import{_ as a,o,c as i,ag as l}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"אודות Dotfiles (HE)","titleTemplate":":title","description":"הדור הבא של תצורת מעטפת. ביצועים גבוהים, מאובטח ומותאם לבינה מלאכותית. מנוהל על ידי Chezmoi. תואם ל-macOS, Linux ו-WSL דרך Dotfiles.","frontmatter":{"title":"אודות Dotfiles","description":"הדור הבא של תצורת מעטפת. ביצועים גבוהים, מאובטח ומותאם לבינה מלאכותית. מנוהל על ידי Chezmoi. תואם ל-macOS, Linux ו-WSL דרך Dotfiles.","lang":"he-IL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"אודות Dotfiles preview","canonical":"/he/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"אודות Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"אודות Dotfiles - Dotfiles (IL)","permalink":"/he/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, configuration, automation, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"הדור הבא של תצורת מעטפת. ביצועים גבוהים, מאובטח ומותאם לבינה מלאכותית. מנוהל על ידי Chezmoi."},{"name":"twitter:title","content":"אודות Dotfiles"},{"name":"og:title","content":"אודות Dotfiles"},{"name":"og:description","content":"הדור הבא של תצורת מעטפת. ביצועים גבוהים, מאובטח ומותאם לבינה מלאכותית. מנוהל על ידי Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - עוצב בפשטות להתאים לחיי המעטפת שלך"},{"name":"og:locale","content":"he_IL"}]},"headers":[],"relativePath":"he/about/index.md","filePath":"he/about/index.md","lastUpdated":1773010926000}'),t={name:"he/about/index.md"};function s(d,e,n,c,r,h){return o(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="אודות-dotfiles" tabindex="-1">אודות Dotfiles <a class="header-anchor" href="#אודות-dotfiles" aria-label="Permalink to &quot;אודות Dotfiles&quot;">​</a></h1><p>התקן המודרני לתצורת מעטפת. בנוי על <strong>Chezmoi</strong> לניהול סביבה מאובטח וחוצה פלטפורמות.</p><h2 id="גלה" tabindex="-1">גלה <a class="header-anchor" href="#גלה" aria-label="Permalink to &quot;גלה&quot;">​</a></h2><p>Dotfiles v0.2.495 הופך את הטרמינל שלך לסביבת עבודה עוצמתית ומאוחדת. בניגוד ל-dotfiles מדור קודם המסתמכים על Makefiles מורכבים או סקריפטי symlink, Dotfiles משתמש בגישה מבוססת תבניות שהיא אטומית, מהירה וניתנת לשחזור.</p><h3 id="מה-חדש" tabindex="-1">מה חדש <a class="header-anchor" href="#מה-חדש" aria-label="Permalink to &quot;מה חדש&quot;">​</a></h3><ul><li><strong>ליבה מודרנית</strong> - חלופות Rust בעלות ביצועים גבוהים מחליפות כלי Unix מדור קודם: <ul><li><strong>Atuin</strong> להיסטוריית מעטפת</li><li><strong>Yazi</strong> לניהול קבצים</li><li><strong>Zellij</strong> לריבוב טרמינלים</li><li><strong>Ghostty</strong> לטרמינל מואץ GPU</li><li><strong>NeoVim</strong> לעריכה מודרנית</li></ul></li><li><strong>אבטחה מקורית</strong> - חתימת SSH מקורית לחלוטין ללא סוכנים של צד שלישי</li><li><strong>מצב אינטראקטיבי</strong> - פקודת <code>dot learn</code> חדשה מדריכה אותך בין התכונות</li></ul><h2 id="התחל" tabindex="-1">התחל <a class="header-anchor" href="#התחל" aria-label="Permalink to &quot;התחל&quot;">​</a></h2><h3 id="דרישות" tabindex="-1">דרישות <a class="header-anchor" href="#דרישות" aria-label="Permalink to &quot;דרישות&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong>, או <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> ו-<strong>Git</strong></li><li><strong>Chezmoi</strong> (מותקן אוטומטית)</li><li><strong>Nerd Font</strong> (לאייקוני טרמינל)</li></ul><h3 id="התקנה" tabindex="-1">התקנה <a class="header-anchor" href="#התקנה" aria-label="Permalink to &quot;התקנה&quot;">​</a></h3><p>הרץ פקודה אחת להתקנת הסט המלא:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>המתקין יבצע:</p><ol><li>התקנת הבינארי של <code>chezmoi</code></li><li>שכפול המאגר</li><li>התקנת חבילות נדרשות דרך Homebrew (macOS) או Apt (Linux)</li><li>החלת התצורה שלך</li></ol><h3 id="חקור" tabindex="-1">חקור <a class="header-anchor" href="#חקור" aria-label="Permalink to &quot;חקור&quot;">​</a></h3><p>לאחר ההתקנה, הפעל מחדש את הטרמינל והרץ:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>זה מפעיל סיור אינטראקטיבי בסביבה החדשה שלך.</p><h2 id="התאם-אישית" tabindex="-1">התאם אישית <a class="header-anchor" href="#התאם-אישית" aria-label="Permalink to &quot;התאם אישית&quot;">​</a></h2><p>התצורה שלך נמצאת ב-<code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # נקודת כניסה למעטפת</span></span>
<span class="line"><span>├── dot_config/             # XDG Base Config (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # היסטוריית מעטפת</span></span>
<span class="line"><span>│   ├── ghostty/            # אמולטור טרמינל</span></span>
<span class="line"><span>│   ├── git/                # תצורת Git</span></span>
<span class="line"><span>│   ├── yazi/               # מנהל קבצים</span></span>
<span class="line"><span>│   ├── zellij/             # מרבב טרמינלים</span></span>
<span class="line"><span>│   ├── zsh/                # תצורת Zsh</span></span>
<span class="line"><span>│   └── shell/              # קיצורים ונתיבים משותפים</span></span>
<span class="line"><span>├── provision/              # סקריפטי מחזור חיים</span></span>
<span class="line"><span>├── install.sh              # מתקין אוניברסלי</span></span>
<span class="line"><span>└── docs/                   # תיעוד</span></span></code></pre></div><h2 id="תרום" tabindex="-1">תרום <a class="header-anchor" href="#תרום" aria-label="Permalink to &quot;תרום&quot;">​</a></h2><p>הצטרף לקהילה. עיין ב<a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">קוד ההתנהגות</a> וב<a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">הנחיות התרומה</a> שלנו.</p><h2 id="פקודות-ליבה" tabindex="-1">פקודות ליבה <a class="header-anchor" href="#פקודות-ליבה" aria-label="Permalink to &quot;פקודות ליבה&quot;">​</a></h2><p>ממשק ה-CLI של <code>dot</code> מציע 53 פקודות מאורגנות לפי קטגוריה.</p><h3 id="ליבה" tabindex="-1">ליבה <a class="header-anchor" href="#ליבה" aria-label="Permalink to &quot;ליבה&quot;">​</a></h3><ul><li><code>dot apply</code> — מחיל שינויי תצורה.</li><li><code>dot sync</code> — שולף את מצב המאגר העדכני ביותר ומחיל.</li><li><code>dot update</code> — מעדכן את המאגר ומחמם מטמונים.</li><li><code>dot add</code> — מוסיף קבצים חדשים למקור Chezmoi.</li><li><code>dot diff</code> — מציג שינויים ממתינים לפני החלה.</li><li><code>dot status</code> — מציג את מצב הקבצים המנוהלים.</li><li><code>dot remove</code> — מסיר קובץ מניהול ומוחק את רשומת המקור.</li><li><code>dot cd</code> — פותח Shell בספריית המקור של Chezmoi.</li><li><code>dot edit</code> — פותח קובץ מנוהל בעורך שלכם.</li><li><code>dot clean-cache</code> — מנקה מטמונים זמניים.</li><li><code>dot prewarm</code> — ממלא מטמונים מראש להפעלת Shell מהירה יותר.</li></ul><h3 id="אבחון" tabindex="-1">אבחון <a class="header-anchor" href="#אבחון" aria-label="Permalink to &quot;אבחון&quot;">​</a></h3><ul><li><code>dot doctor</code> — מאמת נתיבים, כלים ומצב Shell.</li><li><code>dot heal</code> — מתקן באופן אוטומטי מצב חסר או פגום.</li><li><code>dot health</code> — מריץ בדיקת תקינות קלה.</li><li><code>dot verify</code> — בודק שלמות קבצים מול המקור.</li><li><code>dot scorecard</code> — מדפיס ציון איכות תצורה.</li><li><code>dot snapshot</code> — לוכד את המצב הנוכחי להשוואה מאוחרת.</li><li><code>dot smoke-test</code> — מאמת שרשראות כלים מקצה לקצה.</li><li><code>dot chaos</code> — מזריק תקלות לבדיקת ריפוי עצמי.</li><li><code>dot bundle</code> — מייצא חבילת תצורה ניידת.</li><li><code>dot rollback</code> — חוזר ל-snapshot קודם.</li><li><code>dot drift</code> — מזהה שינויים בלתי צפויים בקבצים מנוהלים.</li><li><code>dot history</code> — מציג יומן היסטוריית apply/sync.</li><li><code>dot benchmark</code> — מודד זמן הפעלת Shell.</li><li><code>dot perf</code> — מפרופל אתחול Shell איטי.</li></ul><h3 id="מראה" tabindex="-1">מראה <a class="header-anchor" href="#מראה" aria-label="Permalink to &quot;מראה&quot;">​</a></h3><ul><li><code>dot theme</code> — מחליף ערכת צבעים של הטרמינל.</li><li><code>dot wallpaper</code> — מגדיר טפט שולחן עבודה (macOS).</li><li><code>dot fonts</code> — מתקין או מעדכן Nerd Fonts.</li><li><code>dot tune</code> — מכוונן צפיפות ממשק וסגנון prompt.</li></ul><h3 id="אבטחה" tabindex="-1">אבטחה <a class="header-anchor" href="#אבטחה" aria-label="Permalink to &quot;אבטחה&quot;">​</a></h3><ul><li><code>dot backup</code> — יוצר גיבויי תצורה מוצפנים.</li><li><code>dot encrypt-check</code> — מוודא הצפנת סודות בזמן מנוחה.</li><li><code>dot firewall</code> — מגדיר כללי חומת אש.</li><li><code>dot telemetry</code> — שולט בטלמטריית שימוש אנונימית.</li><li><code>dot dns-doh</code> — מפעיל DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — נועל את המסך מיד.</li><li><code>dot usb-safety</code> — מגביל הרכבה אוטומטית של אחסון USB.</li></ul><h3 id="סודות" tabindex="-1">סודות <a class="header-anchor" href="#סודות" aria-label="Permalink to &quot;סודות&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — מאתחל backend סודות (age / GPG).</li><li><code>dot secrets</code> — מציג רשומות סודות מוצפנות.</li><li><code>dot secrets-create</code> — יוצר סוד מוצפן חדש.</li><li><code>dot ssh-key</code> — מייצר או מסובב זוגות מפתחות SSH.</li><li><code>dot ssh-cert</code> — מבקש תעודת SSH מ-CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — פותח הפעלת עוזר AI אינטראקטיבית.</li><li><code>dot ai-setup</code> — מגדיר מפתחות API לספקי AI.</li><li><code>dot ai-query</code> — שולח prompt חד-פעמי למודל AI.</li><li>עוטפי כלי AI: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="כלים" tabindex="-1">כלים <a class="header-anchor" href="#כלים" aria-label="Permalink to &quot;כלים&quot;">​</a></h3><ul><li><code>dot tools</code> — מציג תחליפי CLI מצורפים ומצבם.</li><li><code>dot new</code> — יוצר קובץ קיצור או פונקציה חדש.</li><li><code>dot sandbox</code> — פותח Shell ארגז חול חד-פעמי.</li><li><code>dot keys</code> — מציג קיצורי מקשים נוכחיים.</li><li><code>dot learn</code> — מתחיל מדריך אינטראקטיבי.</li></ul><h3 id="מטא" tabindex="-1">מטא <a class="header-anchor" href="#מטא" aria-label="Permalink to &quot;מטא&quot;">​</a></h3><ul><li><code>dot upgrade</code> — משדרג Dotfiles לגרסה האחרונה.</li><li><code>dot packages</code> — מציג חבילות מותקנות שמנוהלות על-ידי Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — מציג מידע על גרסה או שימוש</li></ul>`,41)])])}const m=a(t,[["render",s]]);export{u as __pageData,m as default};
